  --overlay-hint-marquee-gap: calc(4 * var(--spacing-unit, 0.25rem));
  --overlay-hint-marquee-fade: 0.75rem;
  /* Mask stops for fade edges (opaque shows, clear hides). */
  --df-mask-opaque: #000;
  --df-mask-clear: transparent;
  --overlay-hint-marquee-mask: linear-gradient(
    90deg,
    var(--df-mask-clear) 0,
    var(--df-mask-opaque) var(--overlay-hint-marquee-fade),
    var(--df-mask-opaque) calc(100% - var(--overlay-hint-marquee-fade)),
    var(--df-mask-clear) 100%
  );

  --spectrum-text-color-1: var(--df-rose-470);
  --spectrum-text-color-2: var(--df-violet-670);
  --spectrum-text-color-3: var(--df-blue-530);
  --spectrum-text-color-4: var(--df-azure-330);
  --spectrum-text-duration: 10s;
  --spectrum-text-ease: ease-in-out;
  --spectrum-text-background-size: 200% auto;

  --df-popover-width: 18rem;
  --df-tooltip-max-width: 16rem;
  --df-tooltip-max-width-detailed: 18rem;
  --df-menu-min-width: 9rem;
  --df-menu-max-height: 24rem;
  --df-submenu-min-width: 18rem;
  --df-submenu-max-height: 28rem;
  --df-toaster-width: 22rem;

  --sidebar: var(--df-neutral-20, var(--df-neutral-50));
  --sidebar-foreground: var(--df-neutral-900);
  --sidebar-primary: var(--df-neutral-850, var(--df-neutral-900));
  --sidebar-primary-foreground: var(--df-neutral-0);
  --sidebar-accent: var(--df-neutral-50);
  --sidebar-accent-foreground: var(--df-neutral-850, var(--df-neutral-900));
  --sidebar-border: var(--df-neutral-100);
  --sidebar-ring: var(--df-neutral-400);
}

[data-df-color-scale="compact"] {
  --primary: var(--df-neutral-900);
  --primary-foreground: var(--df-neutral-0);
  --secondary-foreground: var(--df-neutral-900);
  --accent-foreground: var(--df-neutral-900);
  --sidebar: var(--df-neutral-50);
  --sidebar-primary: var(--df-neutral-900);
  --sidebar-accent-foreground: var(--df-neutral-900);
}

/* Control and affordance sizes for host data-df-density. */
:root,
[data-df-density="cozy"] {
  --df-control-optical-shift: 1px;
  --df-control-height-2xs: calc(6 * var(--spacing-unit));
  --df-control-height-xs: calc(7 * var(--spacing-unit));
  --df-control-height-sm: calc(8 * var(--spacing-unit));
  --df-control-height-md: calc(9 * var(--spacing-unit));
  --df-control-height-lg: calc(10 * var(--spacing-unit));
  --df-control-height-xl: calc(11 * var(--spacing-unit));
  --df-control-height-2xl: calc(12 * var(--spacing-unit));
  --df-affordance-size-2xs: calc(2.5 * var(--spacing-unit));
  --df-affordance-size-xs: calc(3 * var(--spacing-unit));
  --df-affordance-size-sm: calc(4 * var(--spacing-unit));
  --df-affordance-size-md: calc(5 * var(--spacing-unit));
  --df-slider-track-height: calc(3 * var(--spacing-unit));
  --df-slider-line-track-height: calc(1 * var(--spacing-unit));
  --df-slider-line-range-height: calc(2 * var(--spacing-unit));
  --df-slider-line-track-bg: color-mix(
    in oklch,
    var(--foreground) 16%,
    transparent
  );
  --df-slider-thumb-size: var(--df-affordance-size-sm);
  --df-slider-track-height-sm: calc(2 * var(--spacing-unit));
  --df-slider-line-track-height-sm: calc(0.5 * var(--spacing-unit));
  --df-slider-line-range-height-sm: calc(1 * var(--spacing-unit));
  --df-slider-thumb-size-sm: var(--df-affordance-size-xs);
  --df-slider-track-height-lg: calc(5 * var(--spacing-unit));
  --df-slider-line-track-height-lg: calc(2 * var(--spacing-unit));
  --df-slider-line-range-height-lg: calc(4 * var(--spacing-unit));
  --df-slider-thumb-size-lg: var(--df-affordance-size-md);
  --df-slider-header-gap: calc(2 * var(--spacing-unit));
  --df-slider-header-inline-gap: calc(2 * var(--spacing-unit));
  --df-slider-tight-gap: calc(0.5 * var(--spacing-unit));
  --df-slider-label-gap: calc(1.5 * var(--spacing-unit));
  --df-slider-leading-size: calc(4 * var(--spacing-unit));
  --df-slider-vertical-size: calc(48 * var(--spacing-unit));
  --df-slider-marks-gap: calc(2 * var(--spacing-unit));
  --df-slider-vertical-column-gap: calc(5 * var(--spacing-unit));
  --df-slider-marks-track-height: calc(4 * var(--spacing-unit));
  --df-slider-vertical-marks-min-width: calc(10 * var(--spacing-unit));
  --df-slider-value-sep-mix: 72%;
  --df-slider-bubble-pad-inline: calc(2 * var(--spacing-unit));
  --df-slider-bubble-pad-block: calc(0.75 * var(--spacing-unit));
  --df-slider-bubble-offset: calc(2 * var(--spacing-unit));
  --df-slider-bubble-radius: var(--radius-md);
  --df-slider-bubble-clearance: calc(
    var(--df-slider-thumb-size) + var(--df-slider-bubble-offset) +
      var(--df-text-11) + (2 * var(--df-slider-bubble-pad-block))
  );
  --df-slider-thumb-value-clearance: calc(5 * var(--spacing-unit));
  --df-slider-thumb-value-column: calc(12 * var(--spacing-unit));
  --df-slider-thumb-value-gap: calc(1.5 * var(--spacing-unit));
  --df-slider-step-gap: calc(2.5 * var(--spacing-unit));
  --df-tabs-segment-min-height-sm: calc(6.5 * var(--spacing-unit));
  --df-tabs-segment-min-height-md: calc(7.5 * var(--spacing-unit));
  --df-switch-track-height: 18.4px;
  --df-switch-track-width: 32px;
  --df-switch-track-height-sm: 14px;
  --df-switch-track-width-sm: 24px;
  --df-tick-slider-shell-height: calc(14 * var(--spacing-unit));
  --df-tick-slider-tick-height: calc(5 * var(--spacing-unit));
  --df-tick-slider-thumb-height: calc(6 * var(--spacing-unit));
}

[data-df-density="comfortable"] {
  --df-control-height-2xs: calc(7 * var(--spacing-unit));
  --df-control-height-xs: calc(8 * var(--spacing-unit));
  --df-control-height-sm: calc(9 * var(--spacing-unit));
  --df-control-height-md: calc(10 * var(--spacing-unit));
  --df-control-height-lg: calc(11 * var(--spacing-unit));
  --df-control-height-xl: calc(12 * var(--spacing-unit));
  --df-control-height-2xl: calc(13 * var(--spacing-unit));
}

[data-df-density="compact"] {
  --df-control-height-2xs: calc(5 * var(--spacing-unit));
  --df-control-height-xs: calc(6 * var(--spacing-unit));
  --df-control-height-sm: calc(7 * var(--spacing-unit));
  --df-control-height-md: calc(8 * var(--spacing-unit));
  --df-control-height-lg: calc(9 * var(--spacing-unit));
  --df-control-height-xl: calc(10 * var(--spacing-unit));
  --df-control-height-2xl: calc(11 * var(--spacing-unit));
}

.dark {
  --background: var(--df-neutral-950);
  --foreground: var(--df-neutral-0);
  --card: var(--df-neutral-900);
  --card-foreground: var(--df-neutral-0);
  --df-border-glow-stroke: color-mix(
    in oklch,
    var(--df-neutral-0) 12%,
    transparent
  );
  --df-border-glow-light-bg: var(--df-neutral-50);
  --df-border-glow-light-stroke: color-mix(
    in oklch,
    var(--df-neutral-1000) 6%,
    transparent
  );
  --popover: var(--df-neutral-900);
  --popover-foreground: var(--df-neutral-0);
  --primary: var(--df-neutral-100);
  --primary-foreground: var(--df-neutral-900);
  --secondary: var(--df-neutral-800);
  --secondary-foreground: var(--df-neutral-0);
  --muted: var(--df-neutral-800);
  --muted-foreground: var(--df-neutral-400);
  --accent: var(--df-neutral-800);
  --accent-foreground: var(--df-neutral-0);
  --destructive: var(--df-destructive-bright);
  --label-required: var(--destructive);
  --border: color-mix(in oklch, var(--df-neutral-0) 10%, transparent);
  --input: color-mix(in oklch, var(--df-neutral-0) 15%, transparent);
  --ring: var(--df-neutral-500);
  --brand-ink: var(--df-neutral-950);
  --brand-ink-foreground: var(--df-neutral-0);
  --code-bg: var(--code-dark-bg);
  --code-line: var(--code-dark-line);
  --code-gutter: var(--code-dark-gutter);
  --code-text: var(--code-dark-text);
  --code-comment: var(--code-dark-comment);
  --code-string: var(--code-dark-string);
  --code-keyword: var(--code-dark-keyword);
  --code-tag: var(--code-dark-tag);
  --code-punct: var(--code-dark-punct);
  --code-muted: var(--code-dark-muted);
  --chart-1: var(--df-neutral-200);
  --chart-2: var(--df-neutral-500);
  --chart-3: var(--df-neutral-600);
  --chart-4: var(--df-neutral-700);
  --chart-5: var(--df-neutral-800);
  --sidebar: var(--df-neutral-900);
  --sidebar-foreground: var(--df-neutral-0);
  --sidebar-primary: var(--df-brand-500);
  --sidebar-primary-foreground: var(--df-neutral-0);
  --sidebar-accent: var(--df-neutral-800);
  --sidebar-accent-foreground: var(--df-neutral-0);
  --sidebar-border: color-mix(in oklch, var(--df-neutral-0) 10%, transparent);
  --sidebar-ring: var(--df-neutral-500);
  --df-text-mark-yellow: color-mix(
    in oklch,
    var(--df-yellow-green-90) 70%,
    transparent
  );
  --df-text-mark-pink: color-mix(
    in oklch,
    var(--df-magenta-350) 50%,
    transparent
  );
  --df-text-mark-blue: var(--df-blue-320);
  --df-text-mark: var(--df-text-mark-yellow);
  --df-text-mark-foreground: var(--foreground);
  --df-tick-slider-shell-bg: color-mix(
    in oklch,
    var(--muted) 70%,
    var(--background)
  );
  --df-tick-slider-bound-bg: color-mix(
    in oklch,
    var(--background) 55%,
    transparent
  );
  --df-tick-slider-tick-muted: color-mix(
    in oklch,
    var(--foreground) 28%,
    transparent
  );
}

:where(*, *::before, *::after) {
  box-sizing: border-box;
  border-color: var(--border);
  outline-color: color-mix(in oklch, var(--ring) 50%, transparent);
}

html {
  font-family: var(--font-sans), ui-sans-serif, system-ui, sans-serif;
  -webkit-text-size-adjust: 100%;
  tab-size: 4;
  line-height: 1.5;
}

body {
  margin: 0;
  min-height: 100dvh;
  background-color: var(--background);
  color: var(--foreground);
}

:where(img, svg, video) {
  display: block;
  max-width: 100%;
}

:where(canvas) {
  display: block;
}

:where(button, input, optgroup, select, textarea) {
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
  font-weight: inherit;
  letter-spacing: inherit;
  color: inherit;
  margin: 0;
}

:where(button) {
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
}

:where(a) {
  color: inherit;
  text-decoration: inherit;
}

:where(h1, h2, h3, h4, h5, h6, p) {
  margin: 0;
}

:where(ul, ol) {
  margin: 0;
  padding: 0;
  list-style: none;
}

:where(table) {
  border-collapse: collapse;
}

:where(:focus-visible) {
  outline: none;
}

@keyframes df-spin {
  to {
    transform: rotate(360deg);
  }
}

@keyframes df-progress-indeterminate {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(var(--df-progress-indeterminate-travel));
  }
}

@keyframes df-pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

@keyframes df-enter {
  from {
    opacity: var(--df-enter-opacity, 1);
    transform: translate3d(
        var(--df-enter-translate-x, 0),
        var(--df-enter-translate-y, 0),
        0
      )
      scale(var(--df-enter-scale, 1));
  }
}

@keyframes df-exit {
  to {
    opacity: var(--df-exit-opacity, 1);
    transform: translate3d(
        var(--df-exit-translate-x, 0),
        var(--df-exit-translate-y, 0),
        0
      )
      scale(var(--df-exit-scale, 1));
  }
}

@keyframes home-reveal {
  from {
    opacity: 0;
    transform: translateY(var(--df-motion-travel-xl));
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes home-shader-drift {
  0% {
    background-position: 0% 40%, 100% 60%, 50% 50%;
  }
  50% {
    background-position: 80% 20%, 20% 80%, 40% 60%;
  }
  100% {
    background-position: 0% 40%, 100% 60%, 50% 50%;
  }
}

@keyframes home-mesh-float {
  0%,
  100% {
    transform: translate3d(0, 0, 0) scale(1);
  }
  50% {
    transform: translate3d(4%, -3%, 0) scale(1.04);
  }
}

@keyframes home-stage-float {
  0%,
  100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(calc(-1 * var(--df-motion-travel-sm)));
  }
}

@keyframes df-marquee {
  from {
    transform: translateX(0);
  }
  to {
    transform: translateX(calc(-100% - var(--df-marquee-gap)));
  }
}

@keyframes df-tab-progress {
  from {
    transform: scaleX(0);
  }
  to {
    transform: scaleX(1);
  }
}

@keyframes df-spectrum-text {
  0% {
    background-position: 0% 50%;
  }
  25% {
    background-position: 50% 100%;
  }
  50% {
    background-position: 100% 50%;
  }
  75% {
    background-position: 50% 0%;
  }
  100% {
    background-position: 0% 50%;
  }
}

.home-reveal {
  animation: home-reveal var(--df-duration-reveal) var(--df-ease-decelerate) both;
}

.df-reveal {
  opacity: 0;
  transform: translateY(var(--df-reveal-y, var(--df-motion-travel-3xl)));
  transition:
    opacity var(--df-duration-reveal-long) var(--df-ease-decelerate),
    transform var(--df-duration-reveal-long) var(--df-ease-decelerate),
    color var(--df-duration-reveal-long) var(--df-ease-decelerate);
  transition-delay: var(--df-reveal-delay, 0ms);
  will-change: opacity, transform;
}

.df-reveal.is-inview {
  opacity: 1;
  transform: translateY(0);
}

.df-reveal-y-48 {
  --df-reveal-y: var(--df-motion-travel-4xl);
}

.df-reveal-y-72 {
  --df-reveal-y: var(--df-motion-travel-5xl);
}

.df-reveal-emphasis {
  color: color-mix(in oklch, var(--foreground) 25%, transparent);
  opacity: 1;
  transform: none;
}

.df-reveal-emphasis.is-inview {
  color: var(--foreground);
}

.home-grid-fade {
  background-image:
    linear-gradient(
      to right,
      var(--home-grid-line) var(--border-width-hairline),
      transparent var(--border-width-hairline)
    ),
    linear-gradient(
      to bottom,
      var(--home-grid-line) var(--border-width-hairline),
      transparent var(--border-width-hairline)
    );
  background-size: var(--home-grid-size);
  mask-image: linear-gradient(180deg, black 0%, transparent 88%);
}

.home-section-tools {
  background: var(--home-section-tools-wash);
}

.home-preview-frame {
  box-shadow: var(--home-preview-frame-shadow);
}

.home-preview-shader {
  background-image: var(--home-preview-shader-image);
  background-size: 140% 140%, 140% 140%, 140% 140%, 100% 100%;
  animation: home-shader-drift var(--home-shader-drift-duration) ease-in-out
    infinite;
}

.home-preview-mesh {
  background: var(--home-preview-mesh-bg);
}

.home-preview-mesh::before,
.home-preview-mesh::after {
  content: "";
  position: absolute;
  inset: -20%;
  border-radius: var(--radius-full);
  filter: blur(var(--df-blur-mesh));
  animation: home-mesh-float var(--home-mesh-float-duration) ease-in-out infinite;
}

.home-preview-mesh::before {
  background: var(--home-preview-mesh-blob-a);
  left: -10%;
  top: -15%;
}

.home-preview-mesh::after {
  background: var(--home-preview-mesh-blob-b);
  right: -15%;
  bottom: -20%;
  animation-delay: -3s;
}

.home-hero-stage {
  box-shadow: var(--home-hero-stage-shadow);
}

.home-hero-collage-gap {
  margin-top: var(--home-hero-collage-gap);
}

@media (min-width: 640px) {
  :root {
    --home-hero-collage-gap: calc(32 * var(--spacing-unit, 0.25rem));
  }
}

@media (min-width: 1024px) {
  :root {
    --home-hero-collage-gap: calc(36 * var(--spacing-unit, 0.25rem));
  }
}

.home-hero-collage-stage {
  --home-hero-collage-stage-ring: color-mix(
    in oklch,
    var(--border) 70%,
    transparent
  );
  background: var(--muted);
  box-shadow:
    0 0 0 var(--border-width-hairline) var(--home-hero-collage-stage-ring),
    var(--home-hero-collage-stage-elevation);
}

.home-hero-card {
  background: var(--card);
  box-shadow: var(--home-hero-card-shadow);
  will-change: transform, opacity;
  backface-visibility: hidden;
}

.home-hero-card__float {
  will-change: transform;
  backface-visibility: hidden;
}

.home-hero-card-label {
  background: color-mix(in oklch, var(--background) 72%, transparent);
  box-shadow: var(--home-hero-card-label-shadow);
}

.home-stage-frame {
  animation: home-stage-float var(--home-stage-float-duration) ease-in-out
    infinite;
}

.home-stage-frame:nth-child(2) {
  animation-delay: -2.5s;
}

.home-stage-frame:nth-child(3) {
  animation-delay: -4.5s;
}

.df-marquee {
  --df-marquee-gap: calc(3 * var(--spacing-unit, 0.25rem));
  overflow: hidden;
  mask-image: linear-gradient(
    90deg,
    transparent,
    black 8%,
    black 92%,
    transparent
  );
}

.df-marquee-track {
  display: flex;
  gap: var(--df-marquee-gap);
}

.df-marquee-group {
  display: flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: space-around;
  gap: var(--df-marquee-gap);
  min-width: 100%;
  animation: df-marquee var(--df-marquee-duration, 30s) linear infinite;
}

.df-marquee:hover .df-marquee-group {
  animation-play-state: paused;
}

.df-tab-progress {
  transform: scaleX(0);
  transform-origin: left center;
}

.df-tab-progress.is-active {
  animation: df-tab-progress var(--df-tab-duration, 6s) linear forwards;
}

.df-accordion-panel {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows var(--df-duration-panel) var(--df-ease-decelerate);
}

.df-accordion-panel[data-open="true"] {
  grid-template-rows: 1fr;
}

.df-accordion-panel > div {
  overflow: hidden;
}

.df-accordion-chevron {
  transition: transform var(--df-duration-panel) var(--df-ease-decelerate);
}

.df-accordion-chevron[data-open="true"] {
  transform: rotate(180deg);
}

.df-auto-tab-panel {
  opacity: 0;
  transform: translateY(var(--df-motion-travel-lg));
  transition:
    opacity var(--df-duration-panel-soft) var(--df-ease-decelerate),
    transform var(--df-duration-panel-soft) var(--df-ease-decelerate);
  pointer-events: none;
}

.df-auto-tab-panel.is-active {
  opacity: 1;
  transform: translateY(0);
  pointer-events: auto;
}

@media (prefers-reduced-motion: reduce) {
  .home-reveal,
  .home-preview-shader,
  .home-preview-mesh::before,
  .home-preview-mesh::after,
  .home-stage-frame,
  .df-marquee-group,
  .df-tab-progress.is-active,
  .df-spectrum-text-fill,
  .animate-spin,
  .animate-pulse,
  :where([data-df="spinner"] svg),
  .df-spinner svg,
  :where([data-df="progress"][data-state="indeterminate"] .df-progress-indicator),
  .df-progress[data-state="indeterminate"] .df-progress-indicator {
    animation: none !important;
  }

  .df-reveal,
  .df-reveal-emphasis,
  .df-auto-tab-panel,
  .df-accordion-panel,
  .df-accordion-chevron {
    transition: none !important;
  }

  .df-reveal {
    opacity: 1;
    transform: none;
  }

  .df-reveal-emphasis {
    color: var(--foreground);
  }

  .df-auto-tab-panel {
    opacity: 0;
    transform: none;
  }

  .df-auto-tab-panel.is-active {
    opacity: 1;
  }

  .df-tab-progress {
    transform: scaleX(1);
  }
}

:where([data-corner-shape="round"]) {
  --df-corner-shape: var(--df-corner-shape-round);
}

:where([data-corner-shape="smooth"]) {
  --df-corner-shape: var(--df-corner-shape-smooth);
}

.corner-round {
  --df-corner-shape: var(--df-corner-shape-round);
}

.corner-smooth {
  --df-corner-shape: var(--df-corner-shape-smooth);
}

/* Cap-height label centering for leading-none flex chrome. */
:where(
  [data-df="badge"],
  [data-df="choice-chip"],
  [data-df="content-switcher-item"],
  [data-df="tabs-trigger"],
  [data-df="floating-controls-item"],
  [data-df="overlay-hint"],
  [data-df="button"] > [data-slot="badge"]
),
.df-content-switcher-item,
.df-tabs-trigger,
.df-floating-controls-item,
.df-overlay-hint,
.df-btn > [data-slot="badge"] {
  --df-label-line-height: var(--df-leading-none);
