:where([data-df="scroll-area"]) {
  position: relative;
  overflow: hidden;
}

:where([data-df="scroll-area-viewport"]) {
  width: 100%;
  height: 100%;
  border-radius: inherit;
  corner-shape: inherit;
  overflow: auto;
  outline: none;
  scrollbar-width: none;
  -ms-overflow-style: none;
}

/*
 * Scope part selectors to direct children so nested ScrollAreas keep their own
 * variant and space styles. With space=auto and visibility=hover, reserve track
 * inset so the bar can appear without shifting content. Other auto cases reserve
 * inset only when that axis overflows.
 */
:where([data-df="scroll-area"][data-space="auto"][data-visibility="hover"][data-orientation="vertical"] > [data-df="scroll-area-viewport"]),
:where([data-df="scroll-area"][data-space="auto"][data-visibility="hover"][data-orientation="both"] > [data-df="scroll-area-viewport"]),
:where([data-df="scroll-area"][data-space="auto"][data-overflow-y] > [data-df="scroll-area-viewport"]) {
  padding-right: var(--df-scrollbar-track-size);
}

:where([data-df="scroll-area"][data-space="auto"][data-visibility="hover"][data-orientation="horizontal"] > [data-df="scroll-area-viewport"]),
:where([data-df="scroll-area"][data-space="auto"][data-visibility="hover"][data-orientation="both"] > [data-df="scroll-area-viewport"]),
:where([data-df="scroll-area"][data-space="auto"][data-overflow-x] > [data-df="scroll-area-viewport"]) {
  padding-bottom: var(--df-scrollbar-track-size);
}

:where([data-df="scroll-area-viewport"]::-webkit-scrollbar) {
  display: none;
  width: 0;
  height: 0;
}

:where([data-df="scroll-area-scrollbar"]) {
  position: absolute;
  top: var(--df-scrollbar-track-inset);
  right: var(--df-scrollbar-track-inset);
  bottom: var(--df-scrollbar-track-inset);
  display: flex;
  width: var(--df-scrollbar-track-size);
  touch-action: none;
  padding: var(--border-width-hairline);
  transition: opacity var(--df-duration-base), color var(--df-duration-base);
}

:where([data-df="scroll-area-scrollbar"][data-orientation="horizontal"]) {
  top: auto;
  left: var(--df-scrollbar-track-inset);
  right: var(--df-scrollbar-track-inset);
  bottom: var(--df-scrollbar-track-inset);
  height: var(--df-scrollbar-track-size);
  width: auto;
  flex-direction: column;
}

/* Shorten each track when both axes overflow so thumbs do not collide. */
:where([data-df="scroll-area"][data-overflow-x] > [data-df="scroll-area-scrollbar"][data-orientation="vertical"]) {
  bottom: calc(var(--df-scrollbar-track-inset) + var(--df-scrollbar-track-size));
}

:where([data-df="scroll-area"][data-overflow-y] > [data-df="scroll-area-scrollbar"][data-orientation="horizontal"]) {
  right: calc(var(--df-scrollbar-track-inset) + var(--df-scrollbar-track-size));
}

:where([data-df="scroll-area"][data-overflow-x][data-variant="edge"] > [data-df="scroll-area-scrollbar"][data-orientation="vertical"]) {
  bottom: calc(var(--df-scrollbar-track-inset) + var(--df-scrollbar-thickness));
}

:where([data-df="scroll-area"][data-overflow-y][data-variant="edge"] > [data-df="scroll-area-scrollbar"][data-orientation="horizontal"]) {
  right: calc(var(--df-scrollbar-track-inset) + var(--df-scrollbar-thickness));
}

:where([data-df="scroll-area-thumb"]) {
